import{_ as t,o,c as r,ae as a}from"./chunks/framework.BGHOrOyn.js";const p=JSON.parse('{"title":"Required Hardware","description":"","frontmatter":{},"headers":[],"relativePath":"robotics/required-hardware.md","filePath":"robotics/required-hardware.md"}'),i={name:"robotics/required-hardware.md"};function n(s,e,l,h,d,c){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="required-hardware" tabindex="-1">Required Hardware <a class="header-anchor" href="#required-hardware" aria-label="Permalink to &quot;Required Hardware&quot;">​</a></h1><p>The following pages detail the minimum required hardware to have a functioning control system. Where applicable, alternate options are provided when they have been tested and confirmed to work.</p><p>To see each component&#39;s location and how to connects it in the system, check the connection diagrams.</p><ul><li>Autopilot: The autopilot board/flight controller board processes the pilot input and sensor data, and controls the motors, lights, servos, and relays on the vehicle. It runs the ArduSub firmware.</li><li>Companion Computer: The Companion Computer streams video to the Topside Computer, and relays <a href="https://ardupilot.org/dev/docs/mavlink-basics.html" target="_blank" rel="noreferrer">MAVLink</a> communications between the autopilot and the Topside Computer via Ethernet.</li><li>Topside Computer: The topside computer is where the live video feed and telemetry information are received and displayed. It accepts operator input from a joystick to allow controlling the connected vehicle.</li><li>Joystick: A joystick allows the operator to control the vehicle, using stick control movements and button presses.</li><li>Camera: The camera allows the pilot to see and record from the vehicle&#39;s point of view. If paired with a Camera Tilt Mount or other gimbal it can be moved during operation.</li><li>Electronic Speed Controls (ESCs): ESCs are used to control the speed/thrust of motors and thrusters.</li><li>Thrusters: Thrusters are necessary to maneuver an underwater vehicle around. The number and orientation of thrusters on a vehicle determines the number of degrees of freedom (DoF) it may maneuver in.</li><li>Power Sensing Module: A power sensing module provides analog current and voltage sensing to an autopilot onboard the vehicle. It&#39;s used to measure battery level, and how much power the vehicle is using.</li><li>Power Supply: The power supply and distribution system powers all the onboard electronics, including the high current draw of the thrusters. A regulator converts the main supplied power (from a battery or otherwise) into appropriate voltages for the more sensitive electronics - it must ensure a steady supply to avoid the computers restarting and losing control of the vehicle.</li><li>Tether: A tether is a length of cable which connects the Companion Computer to the Topside Computer. It allows low latency high-bandwidth communication to a vehicle in water, which other technologies are poorly suited to.</li></ul><h2 id="results-matching" tabindex="-1">results matching &quot;&quot; <a class="header-anchor" href="#results-matching" aria-label="Permalink to &quot;results matching &quot;&quot;&quot;">​</a></h2><ul><li></li></ul><h3 id="no-results-matching" tabindex="-1">No results matching &quot;&quot; <a class="header-anchor" href="#no-results-matching" aria-label="Permalink to &quot;No results matching &quot;&quot;&quot;">​</a></h3>',7)])])}const m=t(i,[["render",n]]);export{p as __pageData,m as default};
